import React from "react";
import { useNavigate } from "react-router-dom";
import Navbar from "./Navbar";
import Footer from "./Footer";

function Doctors() {
  const navigate = useNavigate();

  const handleViewProfile = (name, specialty) => {
    navigate("/doctorprofile", {
      state: { name, specialty }
    });
  };

  return (
    <div style={styles.container}>

      <Navbar />

      {/* Search */}
      <div style={styles.searchContainer}>
        <input
          type="text"
          placeholder="Search doctors..."
          style={styles.searchInput}
        />
      </div>

      {/* Cards */}
      <div style={styles.cardContainer}>

        <div style={styles.card}>
          <img src="https://cdn-icons-png.flaticon.com/512/387/387561.png" style={styles.image} />
          <h3>Dr. John Smith</h3>
          <p>Cardiologist</p>
          <button style={styles.button}
            onClick={() => handleViewProfile("Dr. John Smith", "Cardiologist")}
          >
            View Profile
          </button>
        </div>

        <div style={styles.card}>
          <img src="https://cdn-icons-png.flaticon.com/512/387/387561.png" style={styles.image} />
          <h3>Dr. Sarah Lee</h3>
          <p>Dermatologist</p>
          <button style={styles.button}
            onClick={() => handleViewProfile("Dr. Sarah Lee", "Dermatologist")}
          >
            View Profile
          </button>
        </div>

        <div style={styles.card}>
          <img src="https://cdn-icons-png.flaticon.com/512/387/387561.png" style={styles.image} />
          <h3>Dr. David Kumar</h3>
          <p>Orthopedic</p>
          <button style={styles.button}
            onClick={() => handleViewProfile("Dr. David Kumar", "Orthopedic")}
          >
            View Profile
          </button>
        </div>

        <div style={styles.card}>
          <img src="https://cdn-icons-png.flaticon.com/512/387/387561.png" style={styles.image} />
          <h3>Dr. Priya Nair</h3>
          <p>Pediatrician</p>
          <button style={styles.button}
            onClick={() => handleViewProfile("Dr. Priya Nair", "Pediatrician")}
          >
            View Profile
          </button>
        </div>

      </div>

      <Footer />

    </div>
  );
}

export default Doctors;

const styles = {
  container: {
    fontFamily: "Arial, sans-serif",
    minHeight: "100vh",
    display: "flex",
    flexDirection: "column",
    backgroundColor: "#f4f6f9",
  },

  searchContainer: {
    textAlign: "center",
    margin: "20px 0",
  },

  searchInput: {
    width: "300px",
    padding: "10px",
    borderRadius: "5px",
    border: "1px solid #ccc",
  },

  cardContainer: {
    flex: 1,
    display: "flex",
    flexWrap: "wrap",
    justifyContent: "center",
    gap: "20px",
    padding: "20px",
  },

  card: {
    backgroundColor: "white",
    width: "220px",
    padding: "20px",
    borderRadius: "10px",
    textAlign: "center",
    boxShadow: "0 4px 10px rgba(0,0,0,0.1)",
  },

  image: {
    width: "90px",
    height: "90px",
    borderRadius: "50%",
    marginBottom: "10px",
  },

  button: {
    marginTop: "10px",
    padding: "8px 15px",
    backgroundColor: "#2c3e50",
    color: "white",
    border: "none",
    borderRadius: "5px",
    cursor: "pointer",
  },
};
